#include <stdio.h>
int main() {
    int T, N;
    scanf("%d", &T);
    while (T--) {
        scanf("%d", &N);
        int arr[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &arr[i]);
        }
        int count = 0;
        for (int i = 1; i < N; i++) {
            if (arr[i] <= arr[i - 1]) {
                count++;
            }
        }
        printf("%d\n", count);
    }
    return 0;
}

