code.Java:
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        while (T-- > 0) {
            int N = scanner.nextInt();
            int[] arr = new int[N];
            for (int i = 0; i < N; i++) {
                arr[i] = scanner.nextInt();
            }
            int count = 0;
            for (int i = 1; i < N; i++) {
                if (arr[i] <= arr[i - 1]) {
                    count++;
                }
            }
            System.out.println(count);
        }
    }
}

